78	                                .listRowSeparator(.hidden)
79	                                .listRowInsets(EdgeInsets(top: 6, leading: 16, bottom: 6, trailing: 16))
80	                        }
81	                        
82	                        if viewModel.isSearching {
83	                            VStack {
84	                                LoaderTextView(title: .ControlCenter.searching)
85	                            }
86	                            .listRowBackground(Color.clear)
87	                            .listRowSeparator(.hidden)
88	                        }
89	                    }
90	                    .scrollIndicators(.hidden)
91	                    .scrollContentBackground(.hidden)
92	                    .listStyle(.plain)
93	                    .safeAreaInset(edge: .bottom, spacing: 0) {
94	                        Spacer()
95	                            .frame(height: 40)
96	                    }
97	                }
98	            }
99	            .background(.dark06)
100	            .toolbar {
101	                CloseButton {
102	                    analyticsEngine.reportEvent(DeviceListAnalyticsEvent.closeClick)
103	                    showDeviceList = false
104	                }
105	            }
106	            .ignoresSafeArea(.all, edges: .bottom)
107	            .navigationTitle(.ControlCenter.devices)
108	            .navigationBarTitleDisplayMode(.automatic)
109	            .scrollBounceBehavior(.basedOnSize, axes: .vertical)
110	        }
111	        .onAppear {
112	            analyticsEngine.reportEvent(DeviceListAnalyticsEvent.mainScreenShow)
113	        }
114	        .task {
115	            viewModel.fetch(currentDeviceIdentifier: deviceContainer.current?.identifier)
116	        }
117	    }
118	    
119	    private func deviceRow(_ radiacode: RadiaCode) -> some View {
120	        DeviceView(
121	            device: radiacode.device,
122	            signal: radiacode.signal
123	        )
124	        .frame(maxWidth: .infinity, alignment: .leading)
125	        .padding(.horizontal, 20)
126	        .padding(.vertical, 12)
127	        .roundedBackground()
128	        .onTapGesture {
129	            analyticsEngine.reportEvent(DeviceListAnalyticsEvent.deviceSelectClick(radiacode.device))
130	            viewModel.connect(radiacode: radiacode)
131	            UIApplication.rootViewController?.dismiss(animated: true)
132	        }
133	    }
134	}
