12	/// Менеджер поиска устройств для подключения
13	protocol DeviceFoundManager {
14	    
15	    /// Observer найденного устройсива
16	    var foundDeviceObserver: PassthroughSubject<RadiaCode, Error> { get }
17	    
18	    /// Observer состояния поиска
19	    var observeSearchingState: AnyPublisher<Bool, Never> { get }
20	    
21	    /// Запускает поиск устройств
22	    func startSearching()
23	
24	    /// Останавливает поиск устройств
25	    func stopSearching()
26	}
27	
28	/// Реализация менеджера поиска устройств для подключения
29	final class DeviceFoundManagerImpl: DeviceFoundManager {
30	    
31	    @Injected(\.bluetoothManager) private var bluetoothManager
32	
33	    var foundDeviceObserver: PassthroughSubject<RadiaCode, Error> = .init()
34	    
35	    var observeSearchingState: AnyPublisher<Bool, Never> {
36	        bluetoothManager.observeScanningStatus
37	    }
38	    
39	    private var searchCounter = Counter()
40	    private var isSearching = false
41	    
42	    private var managerCancellables: Set<AnyCancellable> = .init()
43	
44	    init() {
45	        setupObservers()
46	    }
47	    
48	    func startSearching() {
49	        Task {
50	            await searchCounter.increment()
51	            if !isSearching {
52	                isSearching = true
53	                bluetoothManager.startScan()
54	            }
55	        }
56	    }
57	
58	    func stopSearching() {
59	        Task {
60	            await searchCounter.decrement()
61	            if await searchCounter.value == 0 {
62	                isSearching = false
63	                bluetoothManager.stopScan()
64	            } 
65	        }
66	    }
67	    
68	    private func setupObservers() {
69	        bluetoothManager.observeDevice
70	            .sink { foundDevice in
71	                self.foundDeviceObserver.send(foundDevice)
72	            }.store(in: &managerCancellables)
73	    }
74	}
