27	    struct Device: Hashable {
28	        
29	        let identifier: String
30	        let model: Model
31	        
32	        init(identifier: String, model: String) {
33	            self.identifier = identifier
34	            self.model = Model(rawValue: model)
35	        }
36	        
37	        init?(serialNumber: String) {
38	            let parts = serialNumber.split(separator: "-", omittingEmptySubsequences: false).map(String.init)
39	            guard parts.count >= 3, parts[0] == "RC" else { return nil }
40	            self.identifier = serialNumber
41	            self.model = Model(serialCode: parts[1])
42	        }
43	        
44	        static func == (lhs: Device, rhs: Device) -> Bool {
45	            lhs.identifier == rhs.identifier
46	        }
47	    }
