50	extension RadiaCode {
51	 
52	    enum Family {
53	        case radiaCode10x
54	        case radiaCode11x
55	        case radiaCode103G
56	        case radiaCode41x
57	        
58	        var postFix: String {
59	            switch self {
60	            case .radiaCode10x: return "_10x"
61	            case .radiaCode11x: return "_11x"
62	            case .radiaCode103G: return "_103G"
63	            case .radiaCode41x: return "_41x"
64	            }
65	        }
66	    }
67	    
68	    /// Модели устройств RadiaCode
69	    enum Model: Hashable {
70	
71	        static let defaultName = "RadiaCode"
72	
73	        case radiacode101
74	        case radiacode102
75	        case radiacode103
76	        case radiacode103G
77	        case radiacode110
78	        case radiacodeZero
79	        case radiacode(String)
80	        
81	        typealias RawValue = String
82	
83	        init(rawValue: String) {
84	            switch rawValue {
85	            case "RadiaCode-101": self = .radiacode101
86	            case "RadiaCode-102": self = .radiacode102
87	            case "RadiaCode-103": self = .radiacode103
88	            case "RadiaCode-103G": self = .radiacode103G
89	            case "RadiaCode-110": self = .radiacode110
90	            case "RadiaCode Zero": self = .radiacodeZero
91	            default: self = .radiacode(rawValue)
92	            }
93	        }
94	        
95	        init(serialCode: String) {
96	            switch serialCode {
97	            case "101": self = .radiacode101
98	            case "102": self = .radiacode102
99	            case "103": self = .radiacode103
100	            case "103G": self = .radiacode103G
101	            case "110": self = .radiacode110
102	            case "Zero", "410": self = .radiacodeZero
103	            default: self = .radiacode("RadiaCode-\(serialCode)")
104	            }
105	        }
106	        
107	        var family: Family {
108	            switch self {
109	            case .radiacode101, .radiacode102, .radiacode103:
110	                return .radiaCode10x
111	            case .radiacode103G:
112	                return .radiaCode103G
113	            case .radiacode110:
114	                return .radiaCode11x
115	            case .radiacodeZero:
116	                return .radiaCode41x
117	            case .radiacode(let name):
118	                if name.hasPrefix("RadiaCode-10") {
119	                    return .radiaCode10x
120	                } else if name.hasPrefix("RadiaCode-11") {
121	                    return .radiaCode11x
122	                } else if name.hasPrefix("RadiaCode-41") {
123	                    return .radiaCode41x
124	                } else {
125	                    return .radiaCode10x
126	                }
127	            }
128	        }
129	                
130	        var name: String {
131	            switch self {
132	            case .radiacode101: "RadiaCode-101"
133	            case .radiacode102: "RadiaCode-102"
134	            case .radiacode103: "RadiaCode-103"
135	            case .radiacode103G: "RadiaCode-103G"
136	            case .radiacode110: "RadiaCode-110"
137	            case .radiacodeZero: "RadiaCode-Zero"
138	            case .radiacode(let name): name
139	            }
140	        }
141	    }
142	}
